import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const c=JSON.parse('{"title":"9. テイクアウト管理","description":"","frontmatter":{},"headers":[],"relativePath":"internal/features/09-takeout.md","filePath":"internal/features/09-takeout.md"}'),l={name:"internal/features/09-takeout.md"};function i(o,t,n,s,h,p){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_9-テイクアウト管理" tabindex="-1">9. テイクアウト管理 <a class="header-anchor" href="#_9-テイクアウト管理" aria-label="Permalink to &quot;9. テイクアウト管理&quot;">​</a></h1><p>テイクアウト機能は<strong>proプラン以上</strong>で利用できます。お客さんがオンラインでテイクアウト注文を行い、店舗側で受付・調理・受取の管理を行います。</p><h2 id="_9-1-テイクアウト設定" tabindex="-1">9.1 テイクアウト設定 <a class="header-anchor" href="#_9-1-テイクアウト設定" aria-label="Permalink to &quot;9.1 テイクアウト設定&quot;">​</a></h2><p>テイクアウト機能を利用するには、まず店舗設定で有効化する必要があります。</p><p>管理ダッシュボードの「店舗設定」→「営業設定」から以下を設定します。</p><table tabindex="0"><thead><tr><th>設定項目</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>テイクアウト有効</td><td>OFF</td><td>ONにするとテイクアウト注文を受け付けます</td></tr><tr><td>最低準備時間</td><td>30分</td><td>注文から受取までの最低時間。これより早い時間帯は選択できません</td></tr><tr><td>スロット容量</td><td>5件</td><td>15分間隔の各時間帯で受け付ける最大注文数</td></tr><tr><td>受付開始時間</td><td>10:00</td><td>テイクアウト注文を受け付ける開始時刻</td></tr><tr><td>受付終了時間</td><td>20:00</td><td>テイクアウト注文を受け付ける終了時刻</td></tr><tr><td>オンライン決済</td><td>OFF</td><td>ONにするとオンライン事前決済が可能になります（決済ゲートウェイの設定が必要）</td></tr></tbody></table><h3 id="テイクアウト用qrコード" tabindex="-1">テイクアウト用QRコード <a class="header-anchor" href="#テイクアウト用qrコード" aria-label="Permalink to &quot;テイクアウト用QRコード&quot;">​</a></h3><p>テイクアウト設定画面には、お客さん向けのテイクアウト注文ページのQRコードが自動生成されます。</p><p><strong>QRコードのURL形式：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://あなたのドメイン/customer/takeout.html?store_id=店舗ID</span></span></code></pre></div><p><strong>QRコードの操作ボタン：</strong></p><ul><li>URLをコピー</li><li>QR画像をコピー（クリップボードAPI）</li><li>QRコードを印刷（ブラウザ印刷ダイアログ）</li></ul><div class="tip custom-block"><p class="custom-block-title">QRコードの活用</p><p>テイクアウト用QRコードを店頭のポスターやSNS、チラシに掲載することで、お客さんが簡単にテイクアウト注文画面にアクセスできます。</p></div><hr><h2 id="_9-2-テイクアウト注文管理画面" tabindex="-1">9.2 テイクアウト注文管理画面 <a class="header-anchor" href="#_9-2-テイクアウト注文管理画面" aria-label="Permalink to &quot;9.2 テイクアウト注文管理画面&quot;">​</a></h2><p>管理ダッシュボードの「テイクアウト」タブを選択すると、テイクアウト注文の管理画面が表示されます。</p><h3 id="フィルター" tabindex="-1">フィルター <a class="header-anchor" href="#フィルター" aria-label="Permalink to &quot;フィルター&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フィルター</th><th>説明</th></tr></thead><tbody><tr><td>日付</td><td>注文日を選択（初期値：今日）</td></tr><tr><td>ステータス</td><td>全件 / 受付済み / 決済待ち / 調理中 / 準備完了 / 受取完了</td></tr></tbody></table><h3 id="注文一覧" tabindex="-1">注文一覧 <a class="header-anchor" href="#注文一覧" aria-label="Permalink to &quot;注文一覧&quot;">​</a></h3><p>各注文は以下の情報を持つカードとして表示されます。</p><table tabindex="0"><thead><tr><th>表示要素</th><th>説明</th></tr></thead><tbody><tr><td>受取時間</td><td>HH:MM形式（例：「14:30」）</td></tr><tr><td>ステータスバッジ</td><td>アニメーション付きで色分け</td></tr><tr><td>注文ID</td><td>先頭8文字（大文字）で表示</td></tr><tr><td>お客さん名</td><td>—</td></tr><tr><td>電話番号</td><td>—</td></tr><tr><td>品目サマリー</td><td>品名と数量のカンマ区切り</td></tr><tr><td>合計金額</td><td>—</td></tr><tr><td>メモ</td><td>灰色背景で表示（ある場合のみ）</td></tr><tr><td>アクションボタン</td><td>ステータスに応じたボタン</td></tr></tbody></table><h3 id="ステータスの遷移と操作ボタン" tabindex="-1">ステータスの遷移と操作ボタン <a class="header-anchor" href="#ステータスの遷移と操作ボタン" aria-label="Permalink to &quot;ステータスの遷移と操作ボタン&quot;">​</a></h3><table tabindex="0"><thead><tr><th>現在のステータス</th><th>ボタン</th><th>遷移先</th></tr></thead><tbody><tr><td>pending（受付済み）</td><td>「調理開始」</td><td>preparing</td></tr><tr><td>preparing（調理中）</td><td>「準備完了」（緑色）</td><td>ready</td></tr><tr><td>ready（準備完了）</td><td>「受取完了」（オレンジ色）</td><td>served</td></tr></tbody></table><p><strong>注意：</strong> 「受取完了」に遷移すると、「店頭支払いの場合はレジで会計してください」というメッセージが表示されます。オンライン決済済みでない場合は、POSレジで会計処理を行ってください。</p><h3 id="自動更新" tabindex="-1">自動更新 <a class="header-anchor" href="#自動更新" aria-label="Permalink to &quot;自動更新&quot;">​</a></h3><p>テイクアウト注文一覧は<strong>30秒ごと</strong>に自動更新されます。</p><hr><h2 id="_9-3-お客さん側のテイクアウト注文フロー" tabindex="-1">9.3 お客さん側のテイクアウト注文フロー <a class="header-anchor" href="#_9-3-お客さん側のテイクアウト注文フロー" aria-label="Permalink to &quot;9.3 お客さん側のテイクアウト注文フロー&quot;">​</a></h2><p>お客さんがテイクアウト用QRコードを読み取ると、以下の流れで注文できます。</p><ol><li><strong>テイクアウト設定の読み込み：</strong> 店舗のブランドカラー、ロゴ、営業時間が表示されます</li><li><strong>受取時間の選択：</strong> 15分間隔のタイムスロットが表示され、空きのある時間帯を選択します</li><li><strong>メニューの選択：</strong> 通常のメニュー画面と同じ操作でカートに追加します</li><li><strong>お客さん情報の入力：</strong><ul><li>名前（必須）</li><li>電話番号（必須、10〜11桁、ハイフンなし）</li></ul></li><li><strong>支払方法の選択：</strong> 「店頭支払い」または「オンライン決済」</li><li><strong>注文の確定</strong></li></ol><p><strong>バリデーション：</strong></p><ul><li>品目数の上限（設定による、デフォルト10品）</li><li>金額の上限（設定による、デフォルト¥30,000）</li><li>受取時間が最低準備時間以降であること</li><li>選択した時間帯にスロット空きがあること</li></ul><p><strong>注文確定後：</strong></p><ul><li>オンライン決済の場合：Stripe/Squareの決済ページにリダイレクトされます</li><li>店頭支払いの場合：注文確認画面が表示されます</li><li>注文IDと電話番号でステータスを確認できます</li></ul>',34)])])}const b=d(l,[["render",i]]);export{c as __pageData,b as default};
